begin;

-- Importacao auditavel dos extratos da conta Mercado Pago do Filipe,
-- de janeiro a junho de 2026. A copia identica do PDF de junho foi ignorada.
-- A solicitacao do usuario confirma explicitamente estes lancamentos.
do $$
begin
  if not exists (
    select 1 from public.perfis
    where usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid
      and lower(coalesce(nome, '')) like '%filipe%'
  ) then
    raise exception 'Perfil do Filipe nao encontrado; importacao cancelada.';
  end if;

  if exists (
    select 1 from public.contas
    where usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid
      and lower(nome) = lower('Mercado Pago')
      and id <> '70c10a6f-1882-5411-858a-c465dacecf29'::uuid
  ) then
    raise exception 'Ja existe outra conta chamada Mercado Pago; importacao cancelada.';
  end if;

  if exists (
    select 1 from public.grupos_fontes_panorama
    where usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid
      and lower(nome) = lower('Extratos')
      and id <> '09a8247c-c662-5215-9c7f-010647d1008f'::uuid
  ) then
    raise exception 'Ja existe outro grupo chamado Extratos; importacao cancelada.';
  end if;
end;
$$;

