on conflict (id) do nothing;

do $$
declare
  quantidade integer;
  total_entradas numeric(14, 2);
  total_saidas numeric(14, 2);
  saldo_reconstituido numeric(14, 2);
begin
  select
    count(*),
    coalesce(sum(case
      when natureza = 'receita' then valor
      when natureza = 'transferencia' and conta_destino_id = '70c10a6f-1882-5411-858a-c465dacecf29'::uuid then valor
      else 0
    end), 0),
    coalesce(sum(case when natureza = 'despesa' then valor else 0 end), 0)
  into quantidade, total_entradas, total_saidas
  from public.movimentacoes
  where usuario_id = 'cafaa5dd-2a6a-4d0c-b08b-aa4dd73563e7'::uuid
    and metadados ->> 'importacao_lote' = 'mercado-pago-filipe-2026-01-a-06';

  saldo_reconstituido := 61.36 + total_entradas - total_saidas;
  if quantidade <> 112
     or total_entradas <> 285.85
     or total_saidas <> 337.34
     or saldo_reconstituido <> 9.87 then
    raise exception
      'Validacao dos extratos falhou: % movimentos, entradas %, saidas %, saldo %.',
      quantidade, total_entradas, total_saidas, saldo_reconstituido;
  end if;
end;
$$;

